import{_ as a,c as i,a as t,o as l}from"./app-CEcM0piI.js";const o={};function r(d,e){return l(),i("div",null,e[0]||(e[0]=[t('<ol><li>push(接收任意数量的参数，并将它们添加到数组末尾，返回数组的最新长度</li><li>unshift()在数组开头添加任意多个值，然后返回新的数组长度</li><li>splice传入三个参数，分别是开始位置、0（要删除的元素数量）、插入的元素，返回空数组</li><li>concat()首先会创建一个当前数组的副本，然后再把它的参数添加到副本末尾，最后返回这个新构建的数组，不会影响原始数组</li><li>pop()用于删除数组的最后一项，同时减少数组的<code>length</code> 值，返回被删除的项</li><li>shift()用于删除数组的第一项，同时减少数组的<code>length</code> 值，返回被删除的项</li><li>splice()传入两个参数，分别是开始位置，删除元素的数量，返回包含删除元素的数组</li><li>slice()用于创建一个包含原有数组中一个或多个元素的新数组，不会影响原始数组</li><li>indexOf()返回要查找的元素在数组中的位置，如果没找到则返回-1</li><li>includes()返回要查找的元素在数组中的位置，找到返回<code>true</code>，否则<code>false</code></li><li>find()返回第一个匹配的元素</li><li>reverse()将数组元素逆序排列</li><li>sort()接受一个比较函数，用于判断哪个值应该排在前面</li><li>join()接收一个参数，即字符串分隔符，返回包含所有项的字符串</li><li>some()对数组每一项都运行传入的函数，如果有一项函数返回 true ，则这个方法返回 true</li><li>every()对数组每一项都运行传入的函数，如果对每一项函数都返回 true ，则这个方法返回 true</li><li>forEach()对数组每一项都运行传入的函数，没有返回值</li><li>filter()对数组每一项都运行传入的函数，函数返回 <code>true</code> 的项会组成数组之后返回</li><li>map()对数组每一项都运行传入的函数，返回由每次函数调用的结果构成的数组</li></ol><h1 id="字符串常用方法" tabindex="-1"><a class="header-anchor" href="#字符串常用方法"><span>字符串常用方法</span></a></h1><ol><li>concat用于将一个或多个字符串拼接成一个新字符串</li><li>slice()</li><li>substr()</li><li>substring()这三个方法都返回调用它们的字符串的一个子字符串，而且都接收一或两个参数。</li><li>trim()、trimLeft()、trimRight()删除前、后或前后所有空格符，再返回新的字符串</li><li>repeat()接收一个整数参数，表示要将字符串复制多少次，然后返回拼接所有副本后的结果</li><li>padEnd()复制字符串，如果小于指定长度，则在相应一边填充字符，直至满足长度条件</li><li>toLowerCase()、 toUpperCase()大小写转化</li><li>charAt()返回给定索引位置的字符，由传给方法的整数参数指定</li><li>indexOf()从字符串开头去搜索传入的字符串，并返回位置（如果没找到，则返回 -1 ）</li><li>startWith()、includes()从字符串中搜索传入的字符串，并返回一个表示是否包含的布尔值</li><li>split把字符串按照指定的分割符，拆分成数组中的每一项</li><li>match()接收一个参数，可以是一个正则表达式字符串，也可以是一个<code>RegExp</code>对象，返回数组</li><li>search()接收一个参数，可以是一个正则表达式字符串，也可以是一个<code>RegExp</code>对象，找到则返回匹配索引，否则返回 -1</li><li>replace()接收两个参数，第一个参数为匹配的内容，第二个参数为替换的元素（可用函数）</li></ol><h1 id="和" tabindex="-1"><a class="header-anchor" href="#和"><span>==和===</span></a></h1><p>（==）在比较中会先进行类型转换，再确定操作数是否相等 （ === ）只有两个操作数在不转换的前提下相等才返回 <code>true</code>。即类型相同，值也需相同</p><h1 id="浏览器存储与jwt" tabindex="-1"><a class="header-anchor" href="#浏览器存储与jwt"><span>浏览器存储与JWT</span></a></h1><p>浏览器存储 localStorage 数据持久化存储在磁盘中，用于存储用户偏好设置、缓存数据等。 sessionStorage 数据仅在当前会话（浏览器标签页）用于存储临时数据，如购物车信息。</p><p>JWT（JSON Web Token） 用户登录后，服务器返回JWT，前端将其存储在localStorage或cookie中。后续请求时，在请求头携带JWT，服务器验证后返回数据。 JWT有过期时间，过期后需要重新登录。</p><p>Cookie 存储在客户端的小型文本数据，可设置过期时间、作用域等。可自动发送到服务器，常用于存储用户身份信息。</p><h1 id="vue-router的路由模式与切换方法" tabindex="-1"><a class="header-anchor" href="#vue-router的路由模式与切换方法"><span>Vue Router的路由模式与切换方法</span></a></h1><h4 id="路由模式" tabindex="-1"><a class="header-anchor" href="#路由模式"><span>路由模式</span></a></h4><ul><li>Hash模式 URL中带有<code>#</code>，兼容性好，无需服务器特殊配置。</li><li>History模式 URL无<code>#</code>，URL美观，符合传统URL格式。需要服务器配置，否则刷新页面可能出现404错误。</li></ul><h4 id="路由切换方法" tabindex="-1"><a class="header-anchor" href="#路由切换方法"><span>路由切换方法</span></a></h4><ul><li>push 将新路由添加到历史记录中，可回退到上一个页面。</li><li>replace 替换当前路由，不会添加到历史记录栈中，不可回退到上一个页面。</li></ul><h1 id="javascript的组成" tabindex="-1"><a class="header-anchor" href="#javascript的组成"><span>JavaScript的组成</span></a></h1><h4 id="javascript的组成-1" tabindex="-1"><a class="header-anchor" href="#javascript的组成-1"><span>JavaScript的组成</span></a></h4><ul><li>ECMAScrip：JavaScript的语法标准，规定了基本语法、数据类型、操作符等。</li><li>BOM（浏览器对象模型）：提供与浏览器交互的接口，如<code>window</code>、<code>location</code>、<code>navigator</code>等。</li><li>DOM（文档对象模型）：将HTML文档表示为树形结构，提供操作文档的接口。</li></ul><h4 id="bom的api" tabindex="-1"><a class="header-anchor" href="#bom的api"><span>BOM的API</span></a></h4><ul><li><code>window</code>：全局对象，提供与窗口相关的操作，如<code>window.alert()</code>、<code>window.location</code>等。</li><li><code>location</code>：提供当前页面的URL信息，如<code>location.href</code>、<code>location.reload()</code>等。</li><li><code>navigator</code>：提供浏览器信息，如<code>navigator.userAgent</code>。</li></ul><h4 id="dom的api" tabindex="-1"><a class="header-anchor" href="#dom的api"><span>DOM的API</span></a></h4><ul><li><code>document</code>：代表整个HTML文档，提供查找和操作元素的方法，如<code>document.getElementById()</code>、<code>document.createElement()</code>等。 提供操作元素属性、样式、事件等方法。</li></ul><h4 id="cookie" tabindex="-1"><a class="header-anchor" href="#cookie"><span>Cookie</span></a></h4><ul><li>存储位置：属于DOM，通过<code>document.cookie</code>提供了一种方式来访问由浏览器为当前网页管理的cookie，这更接近于浏览器的行为层面，即BOM的部分功能。因为从根本上说，cookie的管理和存储是由浏览器控制的，</li><li>用途：存储用户身份信息、会话状态等。</li></ul><h1 id="for-in和for-of" tabindex="-1"><a class="header-anchor" href="#for-in和for-of"><span>for in和for of</span></a></h1><h3 id="for-in" tabindex="-1"><a class="header-anchor" href="#for-in"><span>for in</span></a></h3><p>用于<strong>遍历对象的可枚举属性名（键）</strong>。</p><ul><li>遍历的是对象的 <strong>键（key）</strong>。</li><li>可以遍历普通对象、数组、字符串等所有可枚举属性。</li><li>不保证顺序（尤其在对象中），不建议用于遍历数组（顺序可能不符合预期）。</li><li>包括原型链上的可枚举属性（除非使用 <code>hasOwnProperty()</code> 判断）。</li></ul><h3 id="for-of" tabindex="-1"><a class="header-anchor" href="#for-of"><span>for of</span></a></h3><p>用于<strong>遍历可迭代对象的值（value）</strong>。</p><ul><li>遍历的是 <strong>值（value）</strong>。</li><li>支持的类型包括：<code>Array</code>、<code>Map</code>、<code>Set</code>、<code>String</code>、<code>TypedArray</code>、<code>arguments</code> 对象、生成器（Generator）等。</li><li>不适用于普通对象（因为普通对象不可迭代）。</li><li>顺序是可预测的（如数组按索引顺序遍历）。</li></ul><h1 id="事件委托" tabindex="-1"><a class="header-anchor" href="#事件委托"><span>事件委托</span></a></h1><p>事件委托（Event Delegation） 是 JavaScript 中一种高效的事件处理机制，它利用了 事件冒泡 的特性，将事件监听器绑定到父元素上，而不是每个子元素单独绑定。</p><h3 id="事件委托的原理" tabindex="-1"><a class="header-anchor" href="#事件委托的原理"><span>事件委托的原理</span></a></h3><ul><li>在 DOM 中，事件会从目标元素向上传播（冒泡），途中经过它的所有祖先节点。</li><li>利用这一特性，我们可以在父级元素统一监听事件然后根据事件对象中的 <code>target</code> 属性判断具体是哪个子元素触发了事件。</li></ul><h3 id="事件委托的优点" tabindex="-1"><a class="header-anchor" href="#事件委托的优点"><span>事件委托的优点</span></a></h3><ol><li>性能优化 <ul><li>减少绑定的事件监听器数量，尤其适用于动态内容或大量子元素。</li></ul></li><li>支持动态添加的元素 <ul><li>不需要为新添加的子元素重新绑定事件监听器。</li></ul></li><li>代码更简洁、易维护 <ul><li>更少的事件绑定逻辑，提升可维护性。</li></ul></li></ol><p><strong>事件委托就是“以父治子”，通过父元素来管理子元素的事件，提高性能和灵活性。</strong></p><table><thead><tr><th>方式</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>直接绑定事件</td><td>逻辑清晰，控制粒度细</td><td>性能差，不易维护动态内容</td></tr><tr><td>事件委托</td><td>性能好，兼容动态内容</td><td>逻辑稍复杂，需判断事件源</td></tr></tbody></table><h1 id="事件冒泡" tabindex="-1"><a class="header-anchor" href="#事件冒泡"><span>事件冒泡</span></a></h1><p>事件冒泡 是 JavaScript 中 事件传播机制的一部分，它指的是：当一个元素上的事件被触发时，该事件会从当前元素（目标元素）开始，向上传播到其父元素、祖父元素，一直到 <code>window</code> 对象。</p><h3 id="事件冒泡的应用" tabindex="-1"><a class="header-anchor" href="#事件冒泡的应用"><span>事件冒泡的应用</span></a></h3><ul><li>事件委托：利用冒泡机制，在父元素监听子元素的事件。</li><li>统一处理嵌套结构中的交互逻辑</li><li>阻止冒泡：使用 <code>event.stopPropagation()</code> 来阻止事件继续向上传播。</li></ul><table><thead><tr><th>特性</th><th>事件捕获（Capture Phase）</th><th>事件冒泡（Bubbling Phase）</th></tr></thead><tbody><tr><td>执行顺序</td><td>从外层向内层（window → target）</td><td>从内层向外层（target → window）</td></tr><tr><td>默认行为</td><td>否</td><td>是</td></tr><tr><td>是否支持</td><td>支持</td><td>支持</td></tr><tr><td>使用方式</td><td><code>addEventListener(type, fn, true)</code></td><td><code>addEventListener(type, fn, false)</code> 或不写第三个参数</td></tr></tbody></table><h1 id="如何判断是否是数组" tabindex="-1"><a class="header-anchor" href="#如何判断是否是数组"><span>如何判断是否是数组</span></a></h1><p>有以下几种方法可以判断一个值是否为数组：</p><ul><li><p><strong>Array.isArray()方法</strong></p><ul><li>最常用和推荐的方法，直接判断一个值是否为数组。</li><li>示例：<code>Array.isArray(arr)</code></li></ul></li><li><p><strong>Object.prototype.toString.call()</strong></p><ul><li>利用Object的原型方法toString，通过call改变上下文，获取对象的类型信息。</li><li>示例：<code>Object.prototype.toString.call(value) === &#39;[object Array]&#39;</code></li></ul></li><li><p><strong>原型链判断</strong></p><ul><li>通过检查对象的<code>__proto__</code>或<code>prototype</code>属性是否为Array的原型。</li><li>示例：<code>value.__proto__ === Array.prototype</code> 或 <code>Object.getPrototypeOf(value) === Array.prototype</code></li></ul></li><li><p><strong>instanceof操作符</strong></p><ul><li>判断对象是否是某个构造函数的实例。</li><li>示例：<code>value instanceof Array</code></li></ul></li></ul><h1 id="this的指向" tabindex="-1"><a class="header-anchor" href="#this的指向"><span>this的指向</span></a></h1><p>谁调用指向谁 全局环境下的this指向window</p><p>箭头函数：没有this和arguments，捕捉外层的执行环境，继承了该外层的this</p><h1 id="两个对象如何比较" tabindex="-1"><a class="header-anchor" href="#两个对象如何比较"><span>两个对象如何比较</span></a></h1><ol><li>使用JSON.stringifyO方法转化成json字符串比较</li><li>使用es6的object.is0方法</li><li>使用递归的方式</li></ol><h1 id="展开运算符" tabindex="-1"><a class="header-anchor" href="#展开运算符"><span>展开运算符</span></a></h1><p>迭代的对象展开到单独的元素中</p><p>对一维数组深拷贝 对多维数组第，一维深拷贝，其它为浅拷贝 对象的拷贝：一层深拷贝，二层浅拷贝</p><h1 id="实现sleep" tabindex="-1"><a class="header-anchor" href="#实现sleep"><span>实现sleep</span></a></h1><h2 id="基于时间戳的实现" tabindex="-1"><a class="header-anchor" href="#基于时间戳的实现"><span>基于时间戳的实现</span></a></h2><p>开始时获取当前时间戳，将当前时间戳加上目标时间获得结束时间戳 开启while循环，每次循环获取当前时间戳，当前时间戳大于等于目标时间戳时返回</p><p><strong>缺点：</strong> 程序一直在执行，程序不会让线程休眠的，而且所有任务都会暂停，一直执行循环 在sleep过程中程序处于假死状态，不会执行其他任务的</p><h2 id="基于promise实现" tabindex="-1"><a class="header-anchor" href="#基于promise实现"><span>基于promise实现</span></a></h2><p>创建一个新的promise，在promise中执行settimeout定时器</p>',60)]))}const c=a(o,[["render",r]]),s=JSON.parse('{"path":"/front/interview/5/","title":"5 JavaScript","lang":"zh-CN","frontmatter":{"title":"5 JavaScript","createTime":"2025/06/17 18:14:20","permalink":"/front/interview/5/"},"readingTime":{"minutes":9.04,"words":2712},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/面经/5 JavaScript.md","headers":[]}');export{c as comp,s as data};
